object WebhookProxyService extends App {
  implicit val system: ActorSystem = ActorSystem("webhook-proxy-service")
  implicit val materializer: ActorMaterializer = ActorMaterializer()
  implicit val executionContext: ExecutionContextExecutor = system.dispatcher

  import JsonProtocol._
  import akka.http.scaladsl.marshallers.sprayjson.SprayJsonSupport._

  def fetchUrl(url: String): Future[ProxyResponse] = {
    val request = HttpRequest(uri = url)
    
    Http().singleRequest(request).flatMap { response =>
      Unmarshal(response.entity).to[String].map { body =>
        val headers = response.headers.map(h => h.name() -> h.value()).toMap
        ProxyResponse(
          status = response.status.intValue(),
          body = body,
          headers = headers
        )
      }
    }
  }

  val route =
    path("proxy") {
      post {
        entity(as[UrlRequest]) { urlRequest =>
          onComplete(fetchUrl(urlRequest.url)) {
            case Success(proxyResponse) =>
              complete(StatusCodes.OK, proxyResponse)
            case Failure(ex) =>
              complete(StatusCodes.InternalServerError, s"Error fetching URL: ${ex.getMessage}")
          }
        }
      }
    } ~
    path("health") {
      get {
        complete(StatusCodes.OK, "Service is running")
      }
    }

  val bindingFuture = Http().bindAndHandle(route, "0.0.0.0", 8080)

  println(s"Server online at http://0.0.0.0:8080/")

  bindingFuture.onComplete {
    case Success(binding) =>
      println(s"Successfully bound to ${binding.localAddress}")
    case Failure(ex) =>
      println(s"Failed to bind: ${ex.getMessage}")
      system.terminate()
  }
